const AudioCtx = window.AudioContext || window.webkitAudioContext;
let ctx = null;
let soundEnabledGlobal = true;

export function setSoundEnabledGlobal(enabled) {
    soundEnabledGlobal = enabled;
}

function getCtx() {
    if (!ctx) ctx = new AudioCtx();
    if (ctx.state === 'suspended') ctx.resume();
    return ctx;
}

function tone(freq, duration, type = 'sine', vol = 0.3) {
    if (!soundEnabledGlobal) return; // Block all tones if disabled
    try {
        const c = getCtx();
        const osc = c.createOscillator();
        const gain = c.createGain();
        osc.type = type;
        osc.frequency.value = freq;
        gain.gain.setValueAtTime(vol, c.currentTime);
        gain.gain.exponentialRampToValueAtTime(0.001, c.currentTime + duration);
        osc.connect(gain);
        gain.connect(c.destination);
        osc.start();
        osc.stop(c.currentTime + duration);
        // Clean up AudioNodes to prevent memory leaks
        osc.onended = () => { osc.disconnect(); gain.disconnect(); };
    } catch { /* audio not available */ }
}

export function playSound(type) {
    if (!soundEnabledGlobal) return; // Block all SFX if disabled
    if (document.hidden) return;

    switch (type) {
        case 'hit':
            tone(800, 0.15, 'square', 0.2);
            setTimeout(() => tone(600, 0.1, 'square', 0.15), 80);
            break;
        case 'miss':
            tone(300, 0.25, 'sine', 0.12);
            break;
        case 'sunk':
            tone(200, 0.3, 'sawtooth', 0.2);
            setTimeout(() => tone(150, 0.4, 'sawtooth', 0.25), 150);
            setTimeout(() => tone(100, 0.5, 'sawtooth', 0.2), 350);
            break;
        case 'victory':
            [523, 659, 784, 1047].forEach((f, i) =>
                setTimeout(() => tone(f, 0.3, 'sine', 0.25), i * 150)
            );
            break;
        case 'defeat':
            [400, 350, 300, 250].forEach((f, i) =>
                setTimeout(() => tone(f, 0.35, 'sine', 0.2), i * 200)
            );
            break;
        case 'turn':
            tone(880, 0.1, 'sine', 0.15);
            setTimeout(() => tone(1100, 0.15, 'sine', 0.15), 100);
            break;
        case 'chat':
            tone(1200, 0.05, 'sine', 0.08);
            break;
        case 'place':
            tone(500, 0.08, 'sine', 0.1);
            break;
        default:
            break;
    }
}
